using UnityEngine;

/// <summary>Quem está a falar numa DialogueLine.</summary>
public enum DialogueSpeaker
{
    /// <summary>O próprio NPC que está a correr o evento.</summary>
    Self,

    /// <summary>O player.</summary>
    Player,

    /// <summary>Outro NPC presente na cena (ver campo "otherNpc").</summary>
    OtherNpc
}

/// <summary>
/// Uma linha de diálogo com um falante configurável e o texto a mostrar.
///
/// O nome mostrado no balão é, por defeito, o "Display Name" do falante
/// (NpcController.DisplayName ou PlayerIdentity.DisplayName). Para falas sem
/// nome (ex: "???") ou com um nome diferente do habitual, preenche
/// "customName" — esse nome substitui o nome por defeito, seja qual for o
/// Speaker escolhido.
///
/// O texto suporta tags nativas do TMP (&lt;b&gt;, &lt;i&gt;, &lt;u&gt;,
/// &lt;size=...&gt;, &lt;color=...&gt;) e tags próprias processadas pelo
/// DialogueMarkupParser: [wait=0.5], [shake]...[/shake],
/// [highlight]...[/highlight] e [page].
/// </summary>
[System.Serializable]
public class DialogueLine
{
    [Tooltip("Quem está a falar nesta linha.")]
    public DialogueSpeaker speaker = DialogueSpeaker.Self;

    [Tooltip("Necessário apenas quando Speaker = Outro NPC.")]
    public NpcController otherNpc;

    [Tooltip("ID de outro NPC (Etapa 8 — ver \"Npc Id\" no NpcController desse NPC), usado apenas quando Speaker = Outro NPC. Se definido e encontrado, tem prioridade sobre \"otherNpc\".")]
    public string otherNpcId;

    [Tooltip("Se preenchido, substitui o nome por defeito do falante (ex: \"???\", \"Voz Misteriosa\"). Deixa vazio para usar o nome configurado no falante.")]
    public string customName;

    [Tooltip("Texto da fala. Suporta tags TMP (<b>, <i>, <u>, <size=...>, <color=...>) e tags próprias: [wait=0.5], [shake]...[/shake], [highlight]...[/highlight], [page].")]
    [TextArea(2, 5)]
    public string text;

    /// <summary>Resolve o NPC referenciado em "otherNpcId" (Etapa 8) ou, em alternativa, "otherNpc".</summary>
    public NpcController ResolveOtherNpc()
    {
        var byId = NpcController.FindById(otherNpcId);
        return byId != null ? byId : otherNpc;
    }

    /// <summary>Resolve o nome a mostrar no balão para esta linha.</summary>
    public string ResolveSpeakerName(NpcController npc)
    {
        if (!string.IsNullOrEmpty(customName)) return customName;

        switch (speaker)
        {
            case DialogueSpeaker.Self:
                return npc != null ? npc.DisplayName : string.Empty;

            case DialogueSpeaker.Player:
                if (npc != null && npc.Player != null)
                {
                    var identity = npc.Player.GetComponent<PlayerIdentity>();
                    if (identity != null) return identity.DisplayName;
                }
                return "Jogador";

            case DialogueSpeaker.OtherNpc:
                var other = ResolveOtherNpc();
                return other != null ? other.DisplayName : string.Empty;

            default:
                return string.Empty;
        }
    }

    /// <summary>Resolve o Transform do falante desta linha (usado pela calda do balão — Etapa 8).</summary>
    public Transform ResolveSpeakerTransform(NpcController npc)
    {
        switch (speaker)
        {
            case DialogueSpeaker.Self:
                return npc != null ? npc.transform : null;

            case DialogueSpeaker.Player:
                return npc != null ? npc.Player : null;

            case DialogueSpeaker.OtherNpc:
                var other = ResolveOtherNpc();
                return other != null ? other.transform : null;

            default:
                return null;
        }
    }
}
